arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from
            // "Discriminator" to "$type". Preserve the old name so existing
            // 500K documents remain readable and direct SQL queries that
            // reference c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the default id format from "EntityType|Key"
            // to just the raw key value. Preserve the old format so existing
            // documents with ids like "Product|123" can still be found.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

// Reproduces the EF Core 8 "EntityType|Key" id format for new inserts so
// they are consistent with the existing 500K documents.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{entry.Property("Id").CurrentValue}";
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

