class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (preserved in
        // OnModelCreating via HasDiscriminator("Discriminator")).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider removed synchronous query APIs.
        // ToList() → ToListAsync(), First() → FirstAsync(), etc.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

