    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed
            // EF Core 9 defaults to "$type" instead of "Discriminator".
            // Existing 500K documents and direct SQL queries use c.Discriminator.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Resource id format changed
            // EF Core 8: id = "Product|123"   EF Core 9: id = "123"
            // Preserve the old format so existing documents remain accessible
